    // MARK: - Exercise Technique Descriptions
    _ = String(localized: "Техника: Стоя спиной к нижнему блоку, рука отведена назад. Сгибание происходит из положения максимального растяжения длинной головки бицепса. Считается одним из самых эффективных упражнений для роста бицепса согласно современным данным.")
    _ = String(localized: "Хват на ширине плеч. Локти скользят вдоль туловища. Основная нагрузка на трицепс.")
    _ = String(localized: "Нейтральный хват. Сгибайте руки. Работает брахиалис (толщина руки) и предплечье.")
    _ = String(localized: "Руки сзади на скамье. Опускайте таз вниз, сгибая руки. Не уводите таз далеко от скамьи.")
    _ = String(localized: "Стоя. Локти прижаты. Поднимайте штангу по дуге. Не читингуйте спиной. Опускайте под контролем.")
    _ = String(localized: "Стоя у блока. Локти прижаты к бокам. Разгибайте руки вниз. Плечи неподвижны.")
    _ = String(localized: "Биомеханика: Максимальное растяжение длинной головки. Исследования показывают, что работа в растянутой позиции дает больший гипертрофический стимул.")
    _ = String(localized: "Суть: Подъем гантелей супинированным хватом (на бицепс), в верхней точке разворот кистей (пронация) и медленное опускание обратным хватом (на брахиалис и предплечья). Комплексное развитие всей руки.")
    _ = String(localized: "Техника: Лежа животом на вертикальной стороне скамьи Скотта или на наклонной скамье. Руки свисают вертикально вниз. Сгибание происходит без смещения локтей. Максимальная изоляция короткой головки.")
    _ = String(localized: "Руки зафиксированы на пюпитре. Исключает читинг. Полная изоляция бицепса.")
    _ = String(localized: "Лежа на скамье с гантелями, руки выпрямлены вверх. Сгибание происходит только в локтях, гантели опускаются к груди (ладонями к ногам), локти разведены в стороны. Применение: Изолирует латеральную и медиальную головки, исключая помощь длинной головки.")
    _ = String(localized: "Вариация: Опускание штанги не ко лбу, а за голову. Это сильнее растягивает длинную головку трицепса, которая пересекает плечевой сустав. С гантелями: Позволяет использовать нейтральный хват, что безопаснее для локтей.")
    _ = String(localized: "Штанга. Сгибание рук в локтях, гриф ко лбу. Локти смотрят вверх и не гуляют в стороны.")
    _ = String(localized: "Упор на уровне бедер. Опускайтесь с прямой или скругленной спиной (вариации). Поднимайтесь до прямой линии с ногами. Не переразгибайтесь.")
    _ = String(localized: "Тяга каната к лицу (переносице). Локти выше плеч. В конце движения разведите руки ('двойной бицепс'). Для осанки и задней дельты.")
    _ = String(localized: "Хват шире плеч. Тянитесь грудью к перекладине, сводя лопатки. Локти вниз. Не сутультесь в верхней точке.")
    _ = String(localized: "Лежа лопатками на скамье. Опускайте гантель за голову на чуть согнутых руках, максимально растягивая широчайшие. Таз можно слегка опустить.")
    _ = String(localized: "Авторство: Джон Мэдоуз. Техника: Используется Лэндмайн (один конец штанги закреплен). Атлет стоит перпендикулярно грифу, наклонившись вперед. Хват за толстую часть грифа (без рукоятки) пронированной рукой. Локоть тянется вверх и назад, акцентируя нагрузку на заднюю дельту, ромбовидные и внешнюю часть широчайших.")
    _ = String(localized: "Стоя над грифом, наклон корпуса. Тяните гриф к груди, сводя лопатки. Локти прижаты. Избегайте сильной раскачки.")
    _ = String(localized: "Вариация «Прямыми руками» (Straight-Arm Pulldown): Изолирующее упражнение. Атлет стоит, руки прямые, тянет рукоять сверху вниз по дуге к бедрам. Исключает бицепс, активируя широчайшие через функцию разгибания плеча.")
    _ = String(localized: "Сядьте, зафиксируйте ноги. Тяните рукоять к верху груди, прогибаясь в грудном отделе. Опускайте плечи вниз.")
    _ = String(localized: "Упор коленом и рукой в скамью. Спина параллельна полу. Тяните гантель к тазу (движение 'в карман'), локоть строго вверх.")
    _ = String(localized: "Специфика: Выполняется с тяжелой гантелей на большое количество повторений (15–25). Допускается легкий читинг корпусом для преодоления инерции в начале. Развивает ментальную устойчивость и силу хвата.")
    _ = String(localized: "Сидя, спина прямая. Тяните рукоять к животу, сводя лопатки. Плечи не поднимайте к ушам. При возврате чуть подайте корпус вперед для растяжения.")
    _ = String(localized: "Уникальность: Полностью исключает инерцию и нагрузку на поясницу. Атлет лежит на высокой скамье (или использует тренажер), тяга осуществляется строго за счет мышц спины. Это «чистейшая» форма изоляции для верха спины.")
    _ = String(localized: "Наклон корпуса 45°. Спина прямая. Тяните штангу к низу живота, сводя лопатки. Ведите локти вдоль корпуса.")
    _ = String(localized: "Специфика: Вариация жима лежа, где штанга опускается прямо к шее. Ноги часто ставятся на скамью, чтобы убрать прогиб и исключить помощь широчайших. Риски и преимущества: Это упражнение создает экстремальное растяжение грудных мышц и полностью исключает трицепс из работы. Однако оно является травмоопасным для плечевых суставов (риск импиджмента) и требует обязательной страховки.")
    _ = String(localized: "Изометрическое упражнение. Атлет стоит или сидит, сжимая между ладонями два блина от штанги (или одну гантель) перед грудью. Задача — выпрямить руки перед собой, сохраняя адское давление ладонями друг на друга. Применение: Идеально для завершения тренировки (finisher), создавая сильнейший пампинг и улучшая нейромышечную связь.")
    _ = String(localized: "Сядьте плотно, лопатки прижаты. Жмите рукояти вперед. Тренажер задает траекторию, фокусируйтесь только на сокращении грудных.")
    _ = String(localized: "Преимущество унилатеральности: Позволяет каждой руке двигаться независимо, устраняя силовой дисбаланс. Гантели обеспечивают большую амплитуду движения в нижней точке и возможность конвергенции (сведения рук) в верхней, что усиливает пиковое сокращение. Нюанс: В отличие от штанги, вектор силы всегда направлен вертикально вниз, что требует активной стабилизации.")
    _ = String(localized: "Лягте на скамью. Гантели над грудью, лопатки сведены. Опускайте гантели по дуге вниз до растяжения грудных. Выжмите вверх, сводя их в верхней точке. Это упражнение дает большую амплитуду, чем штанга.")
    _ = String(localized: "Скамья 30-45°. Опускайте гантели к плечам, чувствуя растяжение верха груди. Жмите вверх, сводя руки. Предплечья вертикальны в нижней точке.")
    _ = String(localized: "Скамья 30-45°. Опускайте штангу на верх груди (ключицы). Локти держите под углом, не разводите широко. Акцент на верхний пучок грудных мышц.")
    _ = String(localized: "Лягте на скамью, лопатки сведены и плотно прижаты. Хват чуть шире плеч. Опустите штангу на нижнюю часть груди (соски), локти под углом 45°. На выдохе мощно выжмите вверх без отрыва лопаток. Ноги жестко упираются в пол.")
    _ = String(localized: "Опускание производится выше, ближе к ключицам. Важно не допускать чрезмерного прогиба в пояснице, который может нивелировать угол наклона скамьи, превращая упражнение в вариацию горизонтального жима. Угол наклона: Критически важен. 15–30 градусов оптимальны для ключичной (верхней) порции груди. Углы выше 45 градусов катастрофически смещают нагрузку на переднюю дельту, делая упражнение неэффективным для г...")
    _ = String(localized: "Хват шире плеч, локти движутся строго вдоль туловища. Траектория штанги — широкая дуга над животом. Требует помощи партнера при съеме штанги. Биомеханический феномен: Исследования показывают, что супинированный хват (ладони к себе) увеличивает активность верхней части груди на 30% по сравнению с обычным наклонным жимом.")
    _ = String(localized: "Встаньте по центру, корпус чуть вперед. Сводите руки перед собой вниз к поясу, акцентируя внимание на сжатии низа груди. Локти чуть согнуты и зафиксированы.")
    _ = String(localized: "Наклоните корпус вперед, ноги отведите назад. Опускайтесь до 90° в локтях. Локти чуть в стороны для акцента на грудь.")
    _ = String(localized: "Тело в одну линию. Опускайтесь до касания грудью пола. Локти направлены назад под углом 45°, не в стороны. Полная амплитуда.")
    _ = String(localized: "Исключает трицепс. Важно держать локти на уровне плеч для безопасности сустава. Внутренняя часть груди")
    _ = String(localized: "Лежа на скамье, разводите руки в стороны по широкой дуге до растяжения грудных. Локти зафиксированы под тупым углом. Движение 'обнимания бочки'.")
    _ = String(localized: "Техника: Взрывное подтягивание, отпускание перекладины, оборот вокруг своей оси на 360 градусов и повторный хват. Требует пространственной ориентации.")
    _ = String(localized: "Техника: Стоя, гриф на вытянутых руках. Перемещение грифа по дуге от бедра к бедру, не поворачивая корпус. Мышцы кора работают в режиме экстремального торможения инерции.")
    _ = String(localized: "Техника: Широкие отжимания на кольцах, где руки разводятся в стороны при опускании. Огромная нагрузка на грудь.")
    _ = String(localized: "Комплекс: Обратный выпад, затем при вставании — жим грифа противоположной рукой. Координационно сложное упражнение.")
    _ = String(localized: "Взрывной: Тяга до пояса за счет инерции и рывка, быстрый проворот кистей. Медленный (Slow/Strict): Выполняется с ложным хватом (False Grip), без рывков. Чистая сила. На кольцах (Ring Muscle-up): Сложнее из-за нестабильности колец. Требует глубокого хвата.")
    _ = String(localized: "Статус: «Святой Грааль» жимовой статики. Тело параллельно земле, упор только на руки. Биомеханика: Передняя дельта испытывает колоссальную нагрузку. Бицепс работает как стабилизатор локтя (риск разрыва при недостаточной подготовке). Прогрессия: Planche Lean (наклоны) -> Frog Stand (стойка лягушки) -> Tuck Planche -> Straddle Planche -> Full Planche. Push-ups: Отжимания в горизонте без касания ...")
    _ = String(localized: "Вариации: Standing: Стоя двумя руками. Half-Kneeling: Стоя на одном колене, жим одной рукой. Отличная стабилизация кора. Push Press: Жим с помощью ног (швунг). Развивает взрывную силу.")
    _ = String(localized: "Skin The Cat: Проворот тела через кольца/турник из виса в положение виса сзади. Развивает мобильность плеч (экстензия). Back Lever: Удержание тела горизонтально лицом вниз. Нагружает грудные мышцы, бицепсы и плечи в растянутом положении. и «Ласточка» (Skin The Cat)")
    _ = String(localized: "Техника: Отклонение назад, тяга колец к ушам с разведением рук в позу «Y».")
    _ = String(localized: "Техника: Удержание конца грифа у груди (\"намоленная поза\"). Эффект: Позволяет приседать глубже с вертикальной спиной даже людям с плохой мобильностью.")
    _ = String(localized: "Преимущество: Гриф дает точку опоры, решая проблему баланса, свойственную гантелям. Позволяет нагрузить ягодицу и бицепс бедра одной ноги значительным весом.")
    _ = String(localized: "Псевдо-планш (Pseudo Planche Push-ups): Кисти развернуты назад (к ногам), плечи сильно поданы вперед. Биомеханически имитирует жим лежа с огромным весом, нагружая переднюю дельту. Подводящее к горизонту. Лучник (Archer Push-ups): Одна рука прямая (опора), другая сгибается. Переходная ступень к отжиманиям на одной руке. Алмазные (Diamond): Руки вместе, акцент на трицепс и внутреннюю часть груди. Па...")
    _ = String(localized: "Преимущество: Возможность сводить руки в верхней точке (аддукция), как при разводке гантелей, чего нельзя сделать на полу.")
    _ = String(localized: "Анатомия: Широчайшие и прямая мышца живота работают на пределе изометрии. Прогрессия: Tuck (группировка) -> Advanced Tuck (спина прямая) -> One Leg (одна нога прямая) -> Straddle (ноги врозь) -> Full. Вспомогательное: Front Lever Pull-ups (подтягивания в висе) — одно из самых тяжелых упражнений для спины в мире.")
    _ = String(localized: "Динамика: Взрывное движение. Подъем грифа с пола с разворотом корпуса и перехватом в верхней точке. Тренирует передачу усилия от бедер к плечам (трансфер силы для единоборств).")
    _ = String(localized: "На кольцах: Сложнее, чем на брусьях, так как кольца норовят разъехаться.")
    _ = String(localized: "Механика: Нижняя рука толкает, верхняя тянет. Боковые мышцы кора работают на излом.")
    _ = String(localized: "Техника: Боковая планка, где верхняя нога лежит на скамье, а нижняя подтянута к ней. Корпус держится на приводящих мышцах (аддукторах). Профилактика травм паха.")
    _ = String(localized: "Упор лежа на локтях. Тело прямая струна. Пресс и ягодицы напряжены. Поясница не провисает.")
    _ = String(localized: "Вис на турнике. Поднимайте ноги, подкручивая таз вверх (показывайте попу зеркалу). Без раскачки.")
    _ = String(localized: "Биомеханика: Анти-экстензия. Мышцы пресса работают, чтобы не дать пояснице прогнуться под весом тела. Вариация с разведением рук в стороны (на гантелях) — «Iron Cross» на полу.")
    _ = String(localized: "Сидя на полу, отклонитесь назад, ноги на весу. Повороты корпуса влево-вправо. Косые мышцы.")
    _ = String(localized: "Лежа. Отрываем только лопатки, поясница прижата. Выдох на подъеме. Скручивайтесь, а не поднимайтесь.")
    _ = String(localized: "Техника: Наклоны со штангой на плечах. Рычаг силы максимален, поэтому веса должны быть умеренными. Акцент на эксцентрическую фазу работы бицепса бедра.")
    _ = String(localized: "Одна нога сзади на скамье. Приседайте на передней ноге. Корпус чуть вперед для ягодиц, прямо для квадрицепса. Адовое упражнение.")
    _ = String(localized: "Широкий шаг. Заднее колено почти касается пола. Корпус вертикально. Угол в коленях 90°.")
    _ = String(localized: "Роль: Позволяют нагрузить ноги до полного отказа без риска травмы спины, так как таз зафиксирован. В жиме ногами высокая постановка стоп акцентирует ягодицы/бицепс бедра, низкая — квадрицепс. и Жим ногами (Leg Press)")
    _ = String(localized: "Ноги на ширине плеч. Опускайте платформу до 90° в коленях. Не отрывайте поясницу от спинки! Колени не сводите внутрь.")
    _ = String(localized: "Значение: «Золотой стандарт» профилактики травм подколенного сухожилия. Техника: Стоя на коленях, пятки зафиксированы (партнером или под шведской стенкой). Медленное опускание корпуса вперед, сопротивляясь гравитации только силой бицепсов бедра. Возврат — руками (для новичков) или бедрами (элита).")
    _ = String(localized: "Уникальность: Ноги поднимаются сзади, корпус зафиксирован. Растягивает позвоночник (декомпрессия) при одновременной закачке ягодиц и низа спины. Часто используется для реабилитации.")
    _ = String(localized: "Цель: Прямая мышца бедра (квадрицепс) в растянутом положении. Техника: Стоя на коленях, отклонение корпуса назад до касания спиной пяток (в идеале).")
    _ = String(localized: "Прыжки на тумбу (Box Jumps): Развитие взрывной силы. Прыжки в длину (Broad Jumps): Горизонтальная мощность. Выпады с прыжком (Jump Lunges): Интервальная выносливость.")
    _ = String(localized: "Максимальная амплитуда: глубоко вниз (растяжение), высоко вверх (сокращение). Делайте паузы.")
